import{_ as t,c as a,o as r,ag as o}from"./chunks/framework.DRADY2L-.js";const _=JSON.parse('{"title":"Режимы работы SkyZone SteadyView","description":"Модули приема видео (VRX) Skyzone Steadyview, как и большинство современных VRX модулей, содержит 2 приемника, работающих одновременно. Такая схема позволяет...","frontmatter":{"description":"Модули приема видео (VRX) Skyzone Steadyview, как и большинство современных VRX модулей, содержит 2 приемника, работающих одновременно. Такая схема позволяет...","gitAuthors":["mituritsyn","ikherty"]},"headers":[],"relativePath":"ru/settings/skyzone.md","filePath":"ru/settings/skyzone.md","lastUpdated":1774730062000}'),i={name:"ru/settings/skyzone.md"};function s(n,e,p,l,d,y){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="режимы-работы-skyzone-steadyview" tabindex="-1">Режимы работы SkyZone SteadyView <a class="header-anchor" href="#режимы-работы-skyzone-steadyview" aria-label="Permalink to &quot;Режимы работы SkyZone SteadyView&quot;">​</a></h1><p>Модули приема видео (VRX) Skyzone Steadyview, как и большинство современных VRX модулей, содержит 2 приемника, работающих одновременно. Такая схема позволяет реализовывать различные алгоритмы улучшения приема и итоговой картинки. Начиная с аппаратной версии 3.2 Steadyview имеют 4 режима работы.</p><ul><li>В режиме <strong>Div</strong> модуль будет работать в традиционном режиме приема - <a href="/ru/intro/vrx">диверсити</a>. Это означает, что на очки будет выводиться аудио и видеосигнал с приемника, имеющего наибольшую силу сигнала (RSSI).</li></ul><p>Mix режимы нацелены на то, чтобы взять картинку сразу с обоих приеимников и попытаться слить ее воедино, убирая помехи.</p><ul><li><p>Mix1 обеспечивает базовое слияние.</p></li><li><p>Mix2 улучшает стабильность синхронизации. Тут речь идет о синхроимпульсе, который идет в начале каждого PAL/NTSC кадра и нужен для синхронизации, если синхроимпульс из-за помех будет неверно прочтен или потерян, итоговая картинка будет искажена.</p></li><li><p>Mix3 улучшает сигнал синхронизации на основе Mix2, максимизирует стабильность видеоизображения и обеспечивает максимальную совместимость с другими устройствами отображения. В этом режиме яркость видеосигнала будет снижена.</p></li></ul><p>Для корректной работы этих режимов необходимы последние версии прошивки модуля и очков.</p><p>P.S. вольный перевод <a href="https://skyzone.freshdesk.com/support/solutions/articles/151000020976-whats-the-mix1-mix2-mix3-div-mode" target="_blank" rel="noreferrer">статьи</a> с австорскими дополнениями.</p><p>Прошивки и инструкции <a href="https://www.skyzonefpv.com/pages/download" target="_blank" rel="noreferrer">клац</a>.</p><p>Еще инструкции по <a href="https://doggydog.blog/tag/skyzone/" target="_blank" rel="noreferrer">skyzone</a>.</p>',9)])])}const S=t(i,[["render",s]]);export{_ as __pageData,S as default};
